package com.example.biometricauth;

import android.os.Build;

import androidx.annotation.NonNull;
import androidx.annotation.Nullable;
import androidx.biometric.BiometricPrompt;
import androidx.core.content.ContextCompat;
import androidx.fragment.app.FragmentActivity;

import java.util.concurrent.Executor;

public final class BiometricAuthHelper {

    public interface Callback {
        void onAuthenticated();
        void onError(@NonNull String message);
        void onFailed();
    }

    private final FragmentActivity activity;
    private final Callback callback;
    private final Executor executor;
    private final BiometricPrompt biometricPrompt;

    public BiometricAuthHelper(@NonNull FragmentActivity activity, @NonNull Callback callback) {
        this.activity = activity;
        this.callback = callback;
        this.executor = ContextCompat.getMainExecutor(activity);
        this.biometricPrompt = new BiometricPrompt(activity, executor, new BiometricPrompt.AuthenticationCallback() {
            @Override
            public void onAuthenticationSucceeded(@NonNull BiometricPrompt.AuthenticationResult result) {
                callback.onAuthenticated();
            }

            @Override
            public void onAuthenticationError(int errorCode, @NonNull CharSequence errString) {
                callback.onError(errString.toString());
            }

            @Override
            public void onAuthenticationFailed() {
                callback.onFailed();
            }
        });
    }

    public void authenticate(@NonNull String title, @NonNull String subtitle) {
        BiometricPrompt.PromptInfo promptInfo = new BiometricPrompt.PromptInfo.Builder()
                .setTitle(title)
                .setSubtitle(subtitle)
                .setAllowedAuthenticators(
                        androidx.biometric.BiometricManager.Authenticators.BIOMETRIC_STRONG
                                | androidx.biometric.BiometricManager.Authenticators.BIOMETRIC_WEAK
                )
                .setConfirmationRequired(false)
                .build();

        biometricPrompt.authenticate(promptInfo);
    }

    public void cancel() {
        biometricPrompt.cancelAuthentication();
    }
}

